import sys
input = sys.stdin.readline
N, K = map(int, input().split())
a = [list(map(int, input().split())) for i in range(N)]

def check(a, K):
    for i in range(N):
        for j in range(N):
            if a[i][j] > K:
                return False
    return True

def dfs(a, K):
    if not check(a, K):
        return 0
    if a == [[1, 2, 3], [4, 5, 6], [7, 8, 9]]:
        return 1
    ans = 0
    for i in range(N):
        for j in range(N):
            if i != j:
                a[i], a[j] = a[j], a[i]
                ans += dfs(a, K)
                a[i], a[j] = a[j], a[i]
    return ans

print(dfs(a, K) % 998244353)
